from openai import OpenAI
import json

client = OpenAI()  # reads OPENAI_API_KEY from env

response = client.chat.completions.create(
    model="gpt-4o-mini",
    response_format={"type": "json_object"},  # <-- JSON mode
    messages=[
        {
            "role": "system",
            "content": (
                "You are a data-extraction assistant. "
                "Respond ONLY with a JSON object with keys: "
                "name (string), amount (number), currency (string), date (string)."
            ),
        },
        {
            "role": "user",
            "content": "Invoice #1042 from Acme Corp, total $4200.00 USD, issued 2024-11-15.",
        },
    ],
)

raw = response.choices[0].message.content
data = json.loads(raw)   # guaranteed to succeed
print(data)
# {'name': 'Acme Corp', 'amount': 4200.0, 'currency': 'USD', 'date': '2024-11-15'}

import json
from openai import OpenAI

client = OpenAI()

def classify_ticket(ticket_text: str) -> dict:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        response_format={"type": "json_object"},
        messages=[
            {
                "role": "system",
                "content": (
                    "Classify the support ticket. "
                    "Return JSON: {"category": "billing|technical|general", "
                    ""priority": "low|medium|high", "summary": string}"
                ),
            },
            {"role": "user", "content": ticket_text},
        ],
    )
    return json.loads(response.choices[0].message.content)

result = classify_ticket("My credit card was charged twice for order #9981.")
print(result)
# {'category': 'billing', 'priority': 'high', 'summary': 'Duplicate charge for order #9981'}

import OpenAI from "openai";
import { z } from "zod";

const client = new OpenAI(); // reads OPENAI_API_KEY

const PressRelease = z.object({
  company: z.string(),
  ticker: z.string().optional(),
  date: z.string().regex(/^\d{4}-\d{2}-\d{2}$/),
  headline: z.string(),
});

async function extractPressRelease(text) {
  const response = await client.chat.completions.create({
    model: "gpt-4o-mini",
    response_format: { type: "json_object" },
    messages: [
      {
        role: "system",
        content:
          "Extract press release metadata. Return JSON with keys: " +
          "company (string), ticker (string or null), date (YYYY-MM-DD), headline (string).",
      },
      { role: "user", content: text },
    ],
  });

  const raw = JSON.parse(response.choices[0].message.content); // never throws
  return PressRelease.parse(raw); // throws ZodError if schema is wrong
}

// Process a batch
const snippets = [
  "Acme Corp (NYSE: ACM) today announced record Q3 earnings. Nov 7, 2024.",
  "TechStart Ltd revealed its Series B funding of $50M on 2024-10-22.",
];

const results = await Promise.all(snippets.map(extractPressRelease));
console.log(JSON.stringify(results, null, 2));
